window.HK2_LC4 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["He is washing some clothing.", "He is emptying some cabinets.", "He is bending toward some dishware.", "He is closing a machine door."], "optko": ["그는 옷을 세탁하고 있다.", "그는 수납장들을 비우고 있다.", "그는 식기류 쪽으로 몸을 굽히고 있다.", "그는 기계 문을 닫고 있다."], "ans": 2, "audio": "Test04_01.mp3", "img": "hk2_t4_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["They are conversing in a gallery.", "They are admiring some artwork.", "They are painting on a canvas.", "They are pointing at a picture."], "optko": ["그들은 미술관에서 대화를 나누고 있다.", "그들은 예술 작품을 감탄하며 바라보고 있다.", "그들은 캔버스에 그리고 있다.", "그들은 그림을 가리키고 있다."], "ans": 1, "audio": "Test04_02.mp3", "img": "hk2_t4_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["An aircraft is on a runway.", "Some passengers are boarding an airplane.", "An airport is being renovated.", "Some people are standing in an auditorium."], "optko": ["비행기가 활주로 위에 있다.", "몇몇 승객들이 비행기에 탑승하고 있다.", "공항이 보수되고 있다.", "몇몇 사람들이 강당에 서 있다."], "ans": 0, "audio": "Test04_03.mp3", "img": "hk2_t4_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["One of the garage doors is partially open.", "Trash cans have been piled along a street.", "A sign has been posted beside a walkway.", "Some loose bricks are lying on the ground."], "optko": ["차고 문 중 하나가 부분적으로 열려 있다.", "쓰레기통들이 길을 따라 쌓여 있다.", "표지판이 보도 옆에 붙어 있다.", "헐거워진 벽돌들이 땅에 놓여 있다."], "ans": 0, "audio": "Test04_04.mp3", "img": "hk2_t4_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["A woman is fixing a wheelbarrow.", "A woman is pulling on a handle.", "A woman is chopping some wood.", "A woman is reaching into a shed."], "optko": ["한 여자가 손수레를 고치고 있다.", "한 여자가 손잡이를 당기고 있다.", "한 여자가 장작을 패고 있다.", "한 여자가 헛간 안으로 손을 뻗고 있다."], "ans": 3, "audio": "Test04_05.mp3", "img": "hk2_t4_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["An outdoor patio area is being used.", "A hallway leads to a kitchen.", "Some coffee mugs are in a sink.", "Some cups have been set on shelves."], "optko": ["야외 테라스 공간이 사용되고 있다.", "복도는 부엌으로 통한다.", "몇몇 커피잔들이 싱크대 안에 있다.", "몇몇 컵들이 선반에 놓여 있다."], "ans": 3, "audio": "Test04_06.mp3", "img": "hk2_t4_q6.jpg"}, {"n": 7, "part": 2, "q": "Who is the vice president going to be replaced by?", "qko": "부사장은 누구로 대체될 것인가요?", "opts": ["Someone from another branch.", "Edwin Jones is on my team.", "It's time to replace this computer."], "optko": ["다른 지점의 누군가요.", "Edwin Jones는 저희 팀이에요.", "이 컴퓨터를 바꿔야 할 때예요."], "ans": 0, "audio": "Test04_07.mp3"}, {"n": 8, "part": 2, "q": "Where should I take this business suit to have it dry-cleaned?", "qko": "제가 이 정장을 드라이클리닝하려면 어디로 가져가야 할까요?", "opts": ["Our hotel has a laundry service.", "I'm not sure which jacket to buy.", "The room will be thoroughly cleaned."], "optko": ["저희 호텔은 세탁 서비스를 운영합니다.", "무슨 재킷을 사야 할지 모르겠어요.", "이 방은 철저히 청소될 거예요."], "ans": 0, "audio": "Test04_08.mp3"}, {"n": 9, "part": 2, "q": "When are you going to get your passport renewed?", "qko": "당신은 언제 여권을 갱신할 건가요?", "opts": ["By transferring at Boston International Airport.", "Please write down the password.", "Hopefully, sometime this week."], "optko": ["보스턴 국제공항에서 환승함으로써요.", "비밀번호를 써주세요.", "바라건대, 이번 주 중에요."], "ans": 2, "audio": "Test04_09.mp3"}, {"n": 10, "part": 2, "q": "Did Mr. Mason check the loading dock for the delivery?", "qko": "Mr. Mason은 배송을 위해 짐 싣는 부두를 확인했나요?", "opts": ["He's down there now.", "Yes, it was nice to meet you.", "For moving the heavy box."], "optko": ["그는 지금 그곳에 내려가 있어요.", "네, 만나서 반가웠어요.", "그 무거운 상자를 운반하기 위해서요."], "ans": 0, "audio": "Test04_10.mp3"}, {"n": 11, "part": 2, "q": "Are you ready to go for a cup of coffee?", "qko": "커피 한잔 하러 갈 준비가 되셨나요?", "opts": ["No. I need a few more minutes.", "That comes to $3.99.", "OK, I'll prepare the report."], "optko": ["아니요. 저는 몇 분이 더 필요해요.", "3.99달러 되겠습니다.", "네, 제가 그 보고서를 준비할게요."], "ans": 0, "audio": "Test04_11.mp3"}, {"n": 12, "part": 2, "q": "Where did you meet Professor Klein?", "qko": "당신은 어디에서 Klein 교수님을 만나셨나요?", "opts": ["A university instructor.", "We became acquainted at a conference.", "Wherever you want to dine."], "optko": ["대학 강사요.", "저희는 회의에서 알게 되었어요.", "당신이 식사하고 싶은 곳 어디든지요."], "ans": 1, "audio": "Test04_12.mp3"}, {"n": 13, "part": 2, "q": "Why do I need to take the stairwell to the second floor?", "qko": "2층으로 가기 위해 왜 계단을 이용해야 하나요?", "opts": ["The building has nine floors.", "Maintenance is being done on the elevator.", "You don't have to stay for the meal."], "optko": ["그 건물에는 아홉 개의 층들이 있어요.", "엘리베이터가 정비되고 있어요.", "당신은 식사를 위해 남을 필요가 없어요."], "ans": 1, "audio": "Test04_13.mp3"}, {"n": 14, "part": 2, "q": "Do you want to receive a discount today or a voucher to use later?", "qko": "오늘 할인을 받고 싶으세요, 아니면 나중에 사용할 상품권을 받고 싶으세요?", "opts": ["Yes. It's valid until July 30.", "Not for quite a while.", "I'll go with the second option."], "optko": ["네. 그것은 7월 30일까지 유효합니다.", "당분간은 아니에요.", "두 번째 옵션을 선택할게요."], "ans": 2, "audio": "Test04_14.mp3"}, {"n": 15, "part": 2, "q": "How likely is it that the flight to Singapore will be canceled?", "qko": "싱가포르행 비행편이 취소될 가능성은 얼마나 되나요?", "opts": ["It's not on our route.", "That's what I like about her.", "At this point, it's almost certain."], "optko": ["그것은 저희 경로에 없어요.", "그것이 제가 그녀를 좋아하는 이유예요.", "지금으로서는, 거의 확실해요."], "ans": 2, "audio": "Test04_15.mp3"}, {"n": 16, "part": 2, "q": "Will a technician move our fax machine later today?", "qko": "오늘 늦게 기술자가 우리 팩스기를 옮길 건가요?", "opts": ["Some of their equipment was sent back.", "He should arrive soon.", "Tomorrow is supposed to be quite nice."], "optko": ["그들의 장비 일부가 반송되었어요.", "그는 곧 도착할 거예요.", "내일은 꽤 좋을 예정이에요."], "ans": 1, "audio": "Test04_16.mp3"}, {"n": 17, "part": 2, "q": "Where can I get some advice about investment strategies?", "qko": "제가 투자 전략에 관한 조언을 어디에서 얻을 수 있나요?", "opts": ["I'd recommend looking online.", "Yes, you should invest.", "The bank manager took them."], "optko": ["저는 온라인을 보는 것을 추천해요.", "네, 당신은 투자해야 해요.", "은행 관리자가 그것들을 가져갔어요."], "ans": 0, "audio": "Test04_17.mp3"}, {"n": 18, "part": 2, "q": "How about postponing the presentation until the CEO arrives?", "qko": "최고 경영자가 도착할 때까지 발표를 미루는 것이 어때요?", "opts": ["No, I didn't hear the phone ring.", "I printed handouts for everybody.", "OK. I'll begin when she gets here."], "optko": ["아니요, 저는 전화기가 울리는 것을 듣지 못했어요.", "저는 모두를 위해 유인물을 인쇄했어요.", "좋아요. 그녀가 여기 도착하면 시작할게요."], "ans": 2, "audio": "Test04_18.mp3"}, {"n": 19, "part": 2, "q": "I'd like to incorporate a slide show presentation into my speech.", "qko": "저는 제 연설에 슬라이드 쇼 발표를 포함하고 싶어요.", "opts": ["The keynote speaker was excellent.", "A projector will have to be set up.", "For a major corporation."], "optko": ["기조연설자는 훌륭했어요.", "프로젝터가 설치되어야 할 거예요.", "일류 기업을 위해서요."], "ans": 1, "audio": "Test04_19.mp3"}, {"n": 20, "part": 2, "q": "Manufacturing our clothing in America would be more expensive than importing it from China, right?", "qko": "미국에서 저희 의류를 생산하는 것은 중국에서 그것을 수입하는 것보다 더 비쌀 거예요, 그렇죠?", "opts": ["I haven't analyzed the difference.", "While reading the export agreement.", "Well, you should try them on first."], "optko": ["저는 그 차이를 분석해보지 않았어요.", "수출 계약서를 읽는 동안에요.", "음, 당신은 그것들을 먼저 입어봐야 해요."], "ans": 0, "audio": "Test04_20.mp3"}, {"n": 21, "part": 2, "q": "Atlas Hardware had to shut down due to a lack of customers.", "qko": "Atlas 철물점은 손님이 부족해서 문을 닫아야만 했어요.", "opts": ["It must be that new store across the road.", "No, some software is needed.", "But I was there just a week ago."], "optko": ["길 건너편의 저 새로운 가게임이 틀림없어요.", "아니요, 소프트웨어가 필요해요.", "하지만 저는 바로 지난주에 그곳에 갔었는걸요."], "ans": 2, "audio": "Test04_21.mp3"}, {"n": 22, "part": 2, "q": "Cameron is studying to become an accountant, isn't he?", "qko": "Cameron은 회계사가 되기 위해 공부하고 있어요, 그렇지 않나요?", "opts": ["That's right.", "I lost count.", "Check your account balance."], "optko": ["맞아요.", "저는 수를 세다가 도중에 잊었어요.", "당신의 계좌 잔고를 확인하세요."], "ans": 0, "audio": "Test04_22.mp3"}, {"n": 23, "part": 2, "q": "Should I start working as a freelancer, or should I remain at my current company?", "qko": "저는 프리랜서로 일하는 것을 시작해야 할까요, 아니면 현재 회사에 남아 있어야 할까요?", "opts": ["As long as it's for free.", "Being self-employed can be stressful.", "You should promote him."], "optko": ["그것이 무료라면요.", "독자적으로 일하는 것은 스트레스를 받을 수 있어요.", "당신은 그를 승진시켜야 해요."], "ans": 1, "audio": "Test04_23.mp3"}, {"n": 24, "part": 2, "q": "When would you like me to schedule your next appointment?", "qko": "당신의 다음 예약 일정을 언제로 잡아드릴까요?", "opts": ["How about one week from now?", "Make a point of stopping by soon.", "No, at Dr. Blaise's clinic."], "optko": ["일주일 후는 어떤가요?", "반드시 조만간 들르도록 하세요.", "아니요, Dr. Blaise의 병원에서요."], "ans": 0, "audio": "Test04_24.mp3"}, {"n": 25, "part": 2, "q": "I seem to have misplaced my office security badge.", "qko": "제 사무실 보안증을 둔 곳을 잊어버린 것 같아요.", "opts": ["Set it down any place you want.", "You might want to let our supervisor know.", "The guard was hired in April, I believe."], "optko": ["그것을 당신이 원하는 어디에든 두세요.", "우리 관리자에게 알리는 것이 좋겠어요.", "제 생각에 경비원은 4월에 고용된 것 같아요."], "ans": 1, "audio": "Test04_25.mp3"}, {"n": 26, "part": 2, "q": "Would you hold the front door open for me?", "qko": "저를 위해 앞문을 잡아 주시겠어요?", "opts": ["Once I get back from Spain.", "I've got a strong grasp of the subject.", "Sure, let me give you a hand."], "optko": ["제가 스페인에서 돌아오면요.", "저는 그 주제에 대해 확실히 이해했어요.", "물론이죠, 제가 도와드릴게요."], "ans": 2, "audio": "Test04_26.mp3"}, {"n": 27, "part": 2, "q": "I'm trying to find my way to Grosvenor Station.", "qko": "저는 Grosvenor역으로 가기 위해 길을 찾고 있어요.", "opts": ["Let me point it out on this map.", "Just leave it on the train.", "Thanks for dropping me off."], "optko": ["제가 이 지도에서 그곳을 가리켜 보여줄게요.", "그것을 그냥 기차에 두세요.", "저를 데려다주셔서 감사합니다."], "ans": 0, "audio": "Test04_27.mp3"}, {"n": 28, "part": 2, "q": "Should I order protective equipment for the new workers?", "qko": "제가 새로운 직원들을 위해 보호 장비를 주문해야 하나요?", "opts": ["I don't think they were locked.", "Yes, after finding out their sizes.", "The amounts were almost equal."], "optko": ["저는 그것들이 잠겼다고 생각하지 않아요.", "네, 그들의 사이즈를 알아낸 다음에요.", "양은 거의 동일했어요."], "ans": 1, "audio": "Test04_28.mp3"}, {"n": 29, "part": 2, "q": "Mr. Richter is taking inventory of our surplus merchandise, isn't he?", "qko": "Mr. Richter는 우리의 여분의 상품 재고 목록을 만들고 있죠, 그렇지 않나요?", "opts": ["That's usually done on Sundays.", "These necklaces are selling quite well.", "Oh, any extra funding will be saved."], "optko": ["그것은 주로 일요일에 진행돼요.", "이 목걸이들은 꽤 잘 팔리고 있어요.", "아, 어떤 추가 자금이든 저축될 거예요."], "ans": 0, "audio": "Test04_29.mp3"}, {"n": 30, "part": 2, "q": "How many hours did you spend practicing with the choreographer?", "qko": "당신은 안무가와 몇 시간 동안 연습했나요?", "opts": ["We're scheduled to arrive this evening.", "Only two of the trainers could come.", "Honestly, I haven't been keeping track."], "optko": ["저희는 오늘 저녁에 도착할 예정이에요.", "오직 두 명의 트레이너들만 올 수 있었어요.", "솔직히, 저는 기록하지 않고 있었어요."], "ans": 2, "audio": "Test04_30.mp3"}, {"n": 31, "part": 2, "q": "Are insurance policies for motorcycles available through this agency?", "qko": "이 대리점을 통해 오토바이 보험을 이용할 수 있나요?", "opts": ["A list of procedures is hanging in the break room.", "We cover every kind of personal vehicle.", "Throughout most of King National Park."], "optko": ["절차 목록이 휴게실에 걸려 있어요.", "저희는 모든 종류의 개인적인 운송 수단을 포함합니다.", "King 국립 공원의 대부분에 걸쳐서요."], "ans": 1, "audio": "Test04_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test04_32-34.mp3", "qs": [{"n": 32, "q": "Where do the speakers most likely work?", "opts": ["At a medical facility", "At a law firm", "At a community center", "At an educational institution"], "ans": 0, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 33, "q": "What does the man ask the woman to do?", "opts": ["Reschedule a summer vacation", "Attend training workshops", "Work additional hours", "Try a different position"], "ans": 2, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}, {"n": 34, "q": "What does the man say about Jack?", "opts": ["He will take some leave.", "He will move to another office.", "He will return to university.", "He will receive a promotion."], "ans": 0, "ko": "남자는 Jack에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Congratulations on completing your training period, Fiona. Everyone at the health center appreciates all the effort you've put in over the past month. How are things going from your perspective?", "ko": "교육 기간을 마친 것을 축하해요, Fiona. 보건소의 모든 사람들이 지난달 동안 당신이 한 모든 노력을 높이 평가해요. 당신의 관점에서는 상황이 어떻게 되어가고 있나요?"}, {"sp": "W", "en": "Thanks, Mr. Simmons. I'm quite happy, actually. The environment here is much more relaxed than the law office I worked at previously.", "ko": "감사합니다, Mr. Simmons. 사실, 저는 꽤 행복해요. 이곳의 환경은 제가 이전에 일했던 법률 사무소보다 훨씬 더 편안해요."}, {"sp": "M", "en": "Great. That brings me to my other question . . . Would you be willing to do some overtime next month? Jack has booked some vacation time, so we need another receptionist to cover for him on Saturdays.", "ko": "좋아요. 그것은 저의 다른 질문으로 이어지네요… 혹시 다음 달에 초과 근무를 할 의향이 있나요? Jack이 휴가를 예약해서, 우리는 토요일에 그를 대신할 다른 접수 담당자가 필요해요."}, {"sp": "W", "en": "Um, that might be OK. I'll let you know for sure tomorrow.", "ko": "음, 괜찮을 것 같아요. 내일까지 확실히 알려드릴게요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test04_35-37.mp3", "qs": [{"n": 35, "q": "Who most likely are the speakers?", "opts": ["Delivery people", "Real estate agents", "Construction workers", "Government inspectors"], "ans": 2, "ko": "화자들은 누구인 것 같은가?"}, {"n": 36, "q": "What does the woman ask about?", "opts": ["Why a shipment is late", "When a task should be performed", "Where a load should be placed", "Who bought some supplies"], "ans": 1, "ko": "여자는 무엇에 관해 문의하는가?"}, {"n": 37, "q": "What will the man probably do next?", "opts": ["Move a piece of equipment", "Inspect a job site", "Bring a parcel inside", "Clean an outdoor space"], "ans": 0, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Sally, are you busy at the moment? If not, I'd really appreciate a hand. I need to cut the boards that will be used to build the deck in the backyard.", "ko": "Sally, 지금 바빠요? 아니라면, 저를 도와주시면 정말 감사하겠어요. 저는 뒷마당에 목제 테라스를 짓는 데에 사용될 판자들을 잘라야 해요."}, {"sp": "W", "en": "Do you have to do it right away? I've still got a few pieces of siding to attach to the house.", "ko": "그것을 지금 바로 해야 하나요? 저는 집에 붙여야 하는 외장용 자재 몇 조각이 아직 남았어요."}, {"sp": "M", "en": "No, I can wait. I'm going to get the power saw from my truck and move it to the backyard. Let me know when you are ready to begin.", "ko": "아니요, 기다릴 수 있어요. 제가 트럭에서 전기톱을 갖고 와서 뒷마당에 옮겨 놓을게요. 시작할 준비가 되면 제게 알려주세요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음 → 영국식 발음", "audio": "Test04_38-40.mp3", "qs": [{"n": 38, "q": "What is the conversation mainly about?", "opts": ["Exchanging a product", "Extending a warranty", "Refunding a fee", "Repairing an item"], "ans": 3, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 39, "q": "What did the man do yesterday?", "opts": ["Visited a retail outlet", "Purchased a device", "Replaced a component", "Contacted a service center"], "ans": 0, "ko": "남자는 어제 무엇을 했는가?"}, {"n": 40, "q": "What will the man most likely do next?", "opts": ["Select a model", "Complete a form", "Show a receipt", "Make a payment"], "ans": 1, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W1", "en": "Welcome to the Easton Electronics Service Center.", "ko": "Easton 전자 서비스 센터에 오신 것을 환영합니다."}, {"sp": "M", "en": "Hi. The lens on my digital camera is cracked, and I'd like to get it fixed. I bought it last June.", "ko": "안녕하세요. 제 디지털카메라의 렌즈가 금이 가서, 수리를 받고 싶어요. 저는 이것을 작년 6월에 샀어요."}, {"sp": "W1", "en": "OK. But as the one-year warranty has expired, you'll have to pay for the full cost of the repairs.", "ko": "알겠습니다. 하지만 1년의 품질 보증 기간이 만료되어서, 손님께서는 수리의 전체 비용을 지불하셔야 할 거예요."}, {"sp": "M", "en": "Really? Yesterday, I stopped by the store I bought it from, and I was assured that it was still under warranty.", "ko": "정말요? 어제 제가 이것을 구매했던 가게에 들러서 이것이 아직 보증 기간 내에 있다고 확인받았는데요."}, {"sp": "W2", "en": "Excuse me, but did you say you bought it last June?", "ko": "실례지만, 이것을 작년 6월에 구입했다고 하셨나요?"}, {"sp": "M", "en": "Yes.", "ko": "네."}, {"sp": "W2", "en": "Then it is still covered. We offered a two-year extended warranty for that model as a special offer last year.", "ko": "그럼 이건 아직 보상돼요. 저희는 작년에 특별 판매로 그 모델에 대해 2년으로 연장된 품질 보증 기간을 제공했어요."}, {"sp": "W1", "en": "Oh, I didn't realize that. In that case, sir, I'll just need you to complete this form.", "ko": "아, 제가 그걸 몰랐네요. 그렇다면 손님, 이 양식만 빠짐없이 기재해 주시면 됩니다."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test04_41-43.mp3", "qs": [{"n": 41, "q": "What are the speakers mainly discussing?", "opts": ["A software installation", "A training session", "A departmental meeting", "A product demonstration"], "ans": 0, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 42, "q": "What did Mr. Stevens request that staff members do?", "opts": ["Download a program", "Change a security setting", "Provide an account password", "Meet with a technician"], "ans": 1, "ko": "Mr. Stevens는 직원들에게 무엇을 해달라고 요청했는가?"}, {"n": 43, "q": "What will the man most likely do next?", "opts": ["Cancel a workshop", "Send e-mails to clients", "Give instructions to coworkers", "Book a meeting room"], "ans": 2, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Don Stevens from the IT department just told me that a new operating system will be installed on all company computers next Thursday beginning at 10 A.M.", "ko": "IT 부서의 Don Stevens가 다음 주 목요일 오전 10시부터 새로운 운영 체제가 전사 컴퓨터에 설치될 것이라고 방금 저에게 말했어요."}, {"sp": "M", "en": "How long will the work take?", "ko": "그 작업이 얼마나 걸릴까요?"}, {"sp": "W", "en": "About an hour . . . We'll need to find something for our team members to do during that period.", "ko": "한 시간 정도요… 그동안에 우리 팀원들이 할 만한 무언가를 찾아야 할 거예요."}, {"sp": "M", "en": "I'll schedule a training workshop for that morning in the conference room.", "ko": "제가 그날 아침에 회의실에서 교육 워크숍을 하도록 일정을 잡을게요."}, {"sp": "W", "en": "Thanks. One more thing . . . Mr. Stevens asked that everyone disable their computer passwords so that his technicians can access the devices.", "ko": "고마워요. 한 가지 더… Mr. Stevens가 그의 기술자들이 장치들에 접속할 수 있도록 모든 사람들이 컴퓨터 비밀번호를 해제할 것을 요청했어요."}, {"sp": "M", "en": "OK. I'll send an e-mail now to the people on our team telling them to do this.", "ko": "알겠어요. 제가 지금 우리 팀원들에게 그렇게 하도록 전하는 이메일을 보낼게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test04_44-46.mp3", "qs": [{"n": 44, "q": "What most likely is the man's job?", "opts": ["Corporate executive", "Personal driver", "Administrative assistant", "Security guard"], "ans": 1, "ko": "남자의 직업은 무엇인 것 같은가?"}, {"n": 45, "q": "What does the woman say a meeting will be about?", "opts": ["A business convention", "A charity fund-raiser", "A construction project", "An advertising campaign"], "ans": 3, "ko": "여자는 회의가 무엇에 관한 것일 거라고 말하는가?"}, {"n": 46, "q": "What does the man offer to do?", "opts": ["Return at a later time", "Wait for the woman", "Reschedule an appointment", "Review marketing materials"], "ans": 1, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "So, Ms. Greenly, where would you like me to take you next?", "ko": "자, Ms. Greenly, 다음으로 당신을 어디로 모실까요?"}, {"sp": "W", "en": "449 King Street. I have an 11 A.M. appointment scheduled with a few SoundDrive executives to talk about a series of television commercials they want to create.", "ko": "King가 449번지요. 저는 SoundDrive의 몇몇 임원들과 그들이 제작하기를 원하는 일련의 텔레비전 광고들에 관해 이야기하기로 예정된 오전 11시 약속이 있어요."}, {"sp": "M", "en": "I'll head there right away. And would you like me to wait in front of the building until you're done?", "ko": "바로 그곳으로 갈게요. 그리고 다 끝날 때까지 건물 앞에서 기다려 드릴까요?"}, {"sp": "W", "en": "No. You can take your lunch break as I expect to be there for a few hours. I'll call you as soon as I'm finished, and you can return for me then.", "ko": "아니요. 저는 몇 시간 동안 그곳에 있을 것으로 예상되니 점심시간을 가지시면 돼요. 제가 끝나자마자 전화할 테니, 그때 돌아오세요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test04_47-49.mp3", "qs": [{"n": 47, "q": "Where does the man most likely work?", "opts": ["At an accommodation facility", "At a financial institution", "At a clothing retailer", "At a shipping company"], "ans": 2, "ko": "남자는 어디에서 일하는 것 같은가?"}, {"n": 48, "q": "What does the man mean when he says, \"I received several calls this morning\"?", "opts": ["Refund procedures are unclear.", "Customers are making complaints.", "Employees are promoting products.", "Online services are inaccessible."], "ans": 1, "ko": "남자는 \"저는 오늘 아침에 여러 통의 전화를 받았어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 49, "q": "What does the woman ask about?", "opts": ["How much credit will be added to an account", "When a text message notification will be sent", "How long a transaction will take to process", "When an ordered item will be delivered"], "ans": 2, "ko": "여자는 무엇에 관해 문의하는가?"}], "script": [{"sp": "W", "en": "Good morning. My name is Janice Walker, and I just ordered a sweater through your store's Web site. But I noticed that my credit card was charged twice for that item. My order number is 44632.", "ko": "좋은 아침이에요. 제 이름은 Janice Walker이고, 방금 당신 가게의 웹사이트를 통해 스웨터를 주문했어요. 하지만 저는 그 상품에 대해 제 신용 카드가 두 번 결제되었다는 것을 알아챘어요. 제 주문 번호는 44632예요."}, {"sp": "M", "en": "I'm really sorry about that, Ms. Walker. We have been having some issues with our online payment system today. I received several calls this morning.", "ko": "그 점에 대해 정말 죄송합니다, Ms. Walker. 저희는 오늘 온라인 결제 시스템에 약간의 문제를 겪고 있어요. 저는 오늘 아침에 여러 통의 전화를 받았어요."}, {"sp": "W", "en": "I understand. Uh, when can I expect to receive the amount I overpaid?", "ko": "이해해요. 어, 제가 초과 지불한 금액을 언제 받을 수 있을까요?"}, {"sp": "M", "en": "It will take a day or two to process the refund. Once it is completed, the system will send an automatic text message notification to you.", "ko": "환불을 처리하는 데 하루에서 이틀이 걸릴 거예요. 그것이 완료되면, 시스템이 손님께 자동 문자 메시지 알림을 보내드릴 거예요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test04_50-52.mp3", "qs": [{"n": 50, "q": "What does the man ask the woman to do?", "opts": ["Find a coworker", "Move a vehicle", "Repair a device", "Help a customer"], "ans": 3, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}, {"n": 51, "q": "What task does the woman say she will finish later?", "opts": ["Sweeping some aisles", "Throwing out some trash", "Stocking some products", "Changing some price labels"], "ans": 2, "ko": "여자는 어떤 일을 나중에 끝내겠다고 말하는가?"}, {"n": 52, "q": "What does the man suggest doing?", "opts": ["Filling up a container", "Using a credit card again", "Talking to a supervisor", "Moving to another machine"], "ans": 1, "ko": "남자는 무엇을 하라고 제안하는가?"}], "script": [{"sp": "M", "en": "Anita, a man told me he's having trouble using one of the gas pumps. Could you provide him with some assistance? He's wearing a brown coat. I need to stay at the cash register.", "ko": "Anita, 한 남자가 저에게 주유기 중 하나를 사용하는 데 문제를 겪고 있다고 말했어요. 그에게 도움을 주시겠어요? 그는 갈색 코트를 입고 있어요. 저는 계산대에 있어야 해서요."}, {"sp": "W", "en": "I was going to put some bags of chips on the shelves, but I can do that afterward. Did the man give you any more specific information about his issue?", "ko": "저는 선반에 과자 몇 봉지를 진열하려고 했지만, 그건 그 후에 해도 돼요. 그 남자가 그의 문제에 대해 더 구체적인 정보를 주었나요?"}, {"sp": "M", "en": "He's having trouble paying with his credit card. My guess is that he's putting it in backwards. Why don't you try swiping it one more time? If that doesn't work, then maybe the card's magnetic strip is damaged.", "ko": "그는 신용 카드로 결제하는 데 곤란을 겪고 있어요. 제 추측으로 그는 그것을 거꾸로 넣고 있는 것 같아요. 당신이 그것을 한 번 더 긁어보는 게 어때요? 그래도 작동하지 않는다면, 아마 카드의 마그네틱 선이 손상된 걸 거예요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test04_53-55.mp3", "qs": [{"n": 53, "q": "What does the man invite the woman to do?", "opts": ["Go to a new restaurant", "Visit an amusement park", "Attend an exhibition", "Watch a film"], "ans": 3, "ko": "남자는 여자에게 무엇을 하자고 청하는가?"}, {"n": 54, "q": "When will the speakers most likely meet on Saturday?", "opts": ["At 3:00 P.M.", "At 5:00 P.M.", "At 7:00 P.M.", "At 8:00 P.M."], "ans": 3, "ko": "화자들은 토요일에 언제 만날 것 같은가?"}, {"n": 55, "q": "What does the woman say she will do today?", "opts": ["Check a schedule", "Make a reservation", "Purchase some tickets", "Meet some friends"], "ans": 2, "ko": "여자는 오늘 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Mandy, do you have any plans for Saturday evening? The Milford Cinema is showing Paul Dorn's latest movie.", "ko": "Mandy, 토요일 저녁에 계획이 있으신가요? Milford 극장에서 Paul Dorn의 최신 영화를 상영하고 있어요."}, {"sp": "W", "en": "That sounds wonderful. What time do you want to meet? I'm supposed to go to a museum with a friend from 3 to 5 P.M., but I'll be free after that.", "ko": "멋지네요. 몇 시에 만나기를 원해요? 저는 제 친구와 오후 3시부터 5시까지 박물관에 가기로 되어 있지만, 그 이후에는 다른 계획이 없어요."}, {"sp": "M", "en": "I was thinking of going at 8 P.M. I'm having dinner with some colleagues that night, but we should be finished before then.", "ko": "저는 오후 8시에 가는 것을 생각하고 있었어요. 그날 저녁에 동료들과 저녁 식사를 할 거지만, 그전에는 끝날 거예요."}, {"sp": "W", "en": "OK. I'll meet you at the theater at that time. And don't worry about the tickets . . . I'll order them online today. You paid when we went to the amusement park last month, so it's my treat.", "ko": "알겠어요. 그 시간에 극장에서 만나요. 그리고 표에 대해서는 신경 쓰지 마세요… 제가 오늘 온라인으로 그것들을 주문할게요. 지난달에 우리가 놀이공원에 갔을 때 당신이 냈으니, 이번엔 제가 한턱낼게요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test04_56-58.mp3", "qs": [{"n": 56, "q": "What did the man do?", "opts": ["Sliced a freshly made cake", "Requested some dessert", "Confirmed a booking", "Measured some ingredients"], "ans": 3, "ko": "남자는 무엇을 했는가?"}, {"n": 57, "q": "Why does the woman say, \"There's a bag in the pantry\"?", "opts": ["To express confusion", "To explain a mistake", "To offer a solution", "To indicate concern"], "ans": 2, "ko": "여자는 왜 \"식료품 저장실에 자루가 있어요\"라고 말하는가?"}, {"n": 58, "q": "What is mentioned about the man?", "opts": ["He wants a different task.", "He will purchase some flour.", "He forgot about a reservation.", "He was recently hired."], "ans": 3, "ko": "남자에 관해 무엇이 언급되는가?"}], "script": [{"sp": "W", "en": "Jordan, you know you're responsible for making a chocolate cake, right? Some very important customers have made a reservation for tonight, and they've requested a fresh cake be prepared.", "ko": "Jordan, 당신이 초콜릿 케이크를 만드는 것을 담당하고 있다는 것을 아시죠? 매우 중요한 고객 몇 분이 오늘 밤에 예약하셨고, 그들은 갓 만든 케이크가 준비되기를 요청했어요."}, {"sp": "M", "en": "Yes, I know. I measured the sugar, butter, salt, and cocoa powder a few minutes ago. However, the flour jar on the counter is empty, so I can't finish preparing the ingredients.", "ko": "네, 알아요. 저는 몇 분 전에 설탕, 버터, 소금, 그리고 코코아 파우더의 양을 측정했어요. 하지만, 조리대에 있는 밀가루 병이 비어 있어서, 저는 재료들을 준비하는 것을 마칠 수 없어요."}, {"sp": "W", "en": "There's a bag in the pantry. You'll see it just to the right of the door.", "ko": "식료품 저장실에 자루가 있어요. 문 바로 오른쪽에서 그것을 볼 수 있을 거예요."}, {"sp": "M", "en": "Oh, OK. Since I'm new here, I wasn't sure where to look. I'll go get it now.", "ko": "아, 알겠어요. 저는 이곳이 처음이라서, 어디를 찾아봐야 할지 잘 몰랐어요. 지금 가서 그것을 가져올게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test04_59-61.mp3", "qs": [{"n": 59, "q": "What does the woman ask for?", "opts": ["A brand comparison", "A wood sample", "A price estimate", "A product recommendation"], "ans": 3, "ko": "여자는 무엇을 요청하는가?"}, {"n": 60, "q": "What problem does the woman mention?", "opts": ["She ordered too much of a product.", "She did not bring an item.", "She cannot return before 7 P.M.", "She wrote down the wrong amount."], "ans": 1, "ko": "여자는 어떤 문제를 언급하는가?"}, {"n": 61, "q": "What does the man suggest that the woman do?", "opts": ["Visit a different branch", "Return to her residence", "Measure a structure", "Pay for her purchase"], "ans": 1, "ko": "남자는 여자가 무엇을 하라고 제안하는가?"}], "script": [{"sp": "M", "en": "Welcome to Central Hardware. Can I help you find anything?", "ko": "Central 철물점에 오신 것을 환영합니다. 찾으시는 것을 도와드릴까요?"}, {"sp": "W", "en": "Yes. I have a wood fence around my property, and I would like to coat it with something to protect it from the rain. Do you have any suggestions?", "ko": "네. 제 건물 주변에 나무 울타리가 있는데, 이것을 비에 젖지 않도록 보호하기 위해 무언가를 칠하고 싶어요. 추천해 주실 게 있나요?"}, {"sp": "M", "en": "Colman Wood Stain is a good brand. It's easy to apply and not very expensive.", "ko": "Colman Wood Stain이 좋은 상품이에요. 이것은 바르기가 쉽고 많이 비싸지 않아요."}, {"sp": "W", "en": "Great. Um, I don't know how much to buy, though. I wrote down the fence measurements in a notebook, but I forgot it at home.", "ko": "좋아요. 음, 그런데 얼마만큼 사야 할지 모르겠네요. 수첩에 울타리 치수를 적어 놓았는데, 집에 두고 왔어요."}, {"sp": "M", "en": "We're open until 7, so you have time to go home and get it. Once I know the size of the fence, I can tell you how much of the product you'll need.", "ko": "저희는 7시까지 여니까, 댁에 가셔서 그것을 갖고 오실 시간이 있어요. 제가 울타리의 크기를 알면, 손님께서 얼마만큼의 제품이 필요하실지 말씀드릴 수 있어요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test04_62-64.mp3", "qs": [{"n": 62, "q": "Why is the woman late?", "opts": ["A shipment just arrived.", "A factory machine broke down.", "A worker required instructions.", "A client called about an order."], "ans": 3, "ko": "여자는 왜 늦었는가?"}, {"n": 63, "q": "Look at the graphic. Which step will be eliminated?", "opts": ["Step 2", "Step 3", "Step 4", "Step 5"], "ans": 0, "ko": "시각 자료를 보시오. 어떤 단계가 제거될 것인가?"}, {"n": 64, "q": "What does the woman say will happen next year?", "opts": ["A storage facility will be constructed.", "A hiring process will be changed.", "An appliance model will be discontinued.", "An employee orientation will be held."], "ans": 0, "ko": "여자는 내년에 무슨 일이 일어날 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Sorry I'm late. Todd Benson from Prime Appliances phoned to ask when he can expect to receive his next shipment of microwaves from us. Anyway, what do you want to talk about?", "ko": "늦어서 죄송해요. Prime 가전제품사의 Todd Benson이 우리로부터 전자레인지의 다음 배송을 언제 받을 거라고 예상할 수 있는지 물어보려고 전화했어요. 어쨌든, 무엇에 대해서 이야기하고 싶으신가요?"}, {"sp": "M", "en": "Our factory's quality-control protocol. Numerous managers have complained that the process takes too long. This flowchart breaks down the various steps involved.", "ko": "우리 공장의 품질 관리 규약이요. 많은 관리자들이 그 과정이 너무 오래 걸린다고 불평해왔어요. 이 생산 공정도는 관련된 여러 단계들로 나누어져 있어요."}, {"sp": "W", "en": "Hmm . . . How might we improve it?", "ko": "흠… 우리가 이것을 어떻게 개선할 수 있을까요?"}, {"sp": "M", "en": "I think random product sampling is unnecessary. Any problems discovered during this stage would be found during performance testing anyway.", "ko": "저는 무작위 제품 견본 추출이 불필요하다고 생각해요. 이 단계 중에 발견되는 어떤 문제들이든 어차피 수행 능력 검사 중에 발견될 거예요."}, {"sp": "W", "en": "That's true. Let's get rid of that step, then. I'll announce the change later this morning when I tell employees about the new warehouse that will be built next year.", "ko": "맞아요. 그럼, 그 단계를 삭제하죠. 제가 내년에 세워질 새로운 창고에 관해 오늘 아침 늦게 직원들에게 이야기할 때 그 변경사항에 대해 알릴게요."}], "gimg": "hk2_t4_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test04_65-67.mp3", "qs": [{"n": 65, "q": "Who is Mr. Grimes?", "opts": ["An award recipient", "An event host", "A foundation head", "An association donor"], "ans": 2, "ko": "Mr. Grimes는 누구인가?"}, {"n": 66, "q": "Look at the graphic. Where will Mr. Grimes be seated?", "opts": ["At Table 1", "At Table 2", "At Table 3", "At Table 4"], "ans": 3, "ko": "시각 자료를 보시오. Mr. Grimes는 어디에 앉을 것인가?"}, {"n": 67, "q": "What responsibility is given to the man?", "opts": ["Collecting coats from people", "Stacking some chairs", "Passing on some information", "Arranging transportation for guests"], "ans": 2, "ko": "남자에게 무슨 책임이 주어지는가?"}], "script": [{"sp": "M", "en": "There's been a last-minute change to our seating chart for tonight's Writer's House Award Ceremony.", "ko": "오늘 밤 Writer's House 시상식의 좌석 배치도에 막판의 변경이 있어요."}, {"sp": "W", "en": "How come?", "ko": "왜요?"}, {"sp": "M", "en": "Apparently, Gregory Grimes, the director of the Writer's House Foundation, recently sprained his ankle. He has asked to be seated at a table that is easy to access.", "ko": "듣자 하니, Writer's House 재단의 책임자인 Gregory Grimes가 최근에 그의 발목을 삐었대요. 그는 접근하기 쉬운 테이블에 앉는 것을 요청했어요."}, {"sp": "W", "en": "OK. I will move him from the one directly in front of the stage to the one closest to the entrance.", "ko": "알겠어요. 제가 그를 무대 바로 앞의 자리에서 입구와 가장 가까운 자리로 옮길게요."}, {"sp": "M", "en": "Yes, that'll definitely be more convenient.", "ko": "네, 확실히 그게 훨씬 더 편리할 거예요."}, {"sp": "W", "en": "Right. Now, I need you to wait near the entrance. When Mr. Grimes arrives, please tell him about the relocation once he has a chance to check his coat.", "ko": "맞아요. 이제, 당신이 입구 근처에서 대기해주셨으면 해요. Mr. Grimes가 도착하면, 그가 코트를 맡기자마자 그에게 재배치에 대해 말해주세요."}], "gimg": "hk2_t4_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test04_68-70.mp3", "qs": [{"n": 68, "q": "Look at the graphic. Which session will be postponed?", "opts": ["Basic safety", "Machine maintenance", "Warehouse regulations", "Quality control"], "ans": 1, "ko": "시각 자료를 보시오. 어느 강의가 연기될 것인가?"}, {"n": 69, "q": "What did the man create?", "opts": ["A name tag", "A sign-up sheet", "A training booklet", "A program"], "ans": 2, "ko": "남자는 무엇을 만들었는가?"}, {"n": 70, "q": "Where will the man most likely go next?", "opts": ["To a conference room", "To a packaging area", "To a warehouse", "To an office"], "ans": 3, "ko": "남자는 다음에 어디로 갈 것 같은가?"}], "script": [{"sp": "W", "en": "Mr. Rolling just informed me that one of our training sessions tomorrow has to be moved to the afternoon so the new staff can take a tour of the factory.", "ko": "새로운 직원들이 공장을 견학할 수 있도록 내일 우리 교육 강의들 중 하나가 오후로 옮겨져야 한다고 Mr. Rolling이 방금 저에게 알려줬어요."}, {"sp": "M", "en": "I say we reschedule the session beginning at 9 o'clock. The material is quite complicated, and we would have more time to cover it if we held the workshop later in the day.", "ko": "저는 9시에 시작하는 강의 일정을 변경해야 할 것 같아요. 그 자료가 꽤 복잡해서, 우리가 그날 늦게 그 워크숍을 연다면 그것을 다루는 데 더 많은 시간을 갖게 될 거예요."}, {"sp": "W", "en": "I was thinking we should postpone the one on warehouse regulations, but we can go with your suggestion. On a side note, did you make the instructional booklet for the quality-control session?", "ko": "저는 우리가 창고 규정들에 관한 것을 연기해야 한다고 생각했지만, 당신의 제안대로 해도 되겠네요. 여담이지만, 품질 관리 강의를 위한 교육용 책자를 만들었나요?"}, {"sp": "M", "en": "Yeah. It's in my office.", "ko": "네. 제 사무실에 있어요."}, {"sp": "W", "en": "Excellent. Please go and get it now. I'll wait for you in the conference room.", "ko": "훌륭해요. 지금 가서 그것을 가져와 주세요. 저는 회의실에서 당신을 기다릴게요."}], "gimg": "hk2_t4_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test04_71-73.mp3", "qs": [{"n": 71, "q": "What is the talk mainly about?", "opts": ["The schedule of a train", "Some details regarding a boat ride", "Some rules for a wildlife park", "The amenities of a resort"], "ans": 1, "ko": "담화는 주로 무엇에 관한 것인가?"}, {"n": 72, "q": "What does the speaker say is located on the lower level?", "opts": ["Some luggage", "A seat", "A vehicle", "Some refreshments"], "ans": 2, "ko": "화자는 아래층에 무엇이 있다고 말하는가?"}, {"n": 73, "q": "What does the speaker suggest doing?", "opts": ["Watching for wildlife", "Taking out a ticket", "Forming a line", "Reviewing an area map"], "ans": 0, "ko": "화자는 무엇을 하라고 제안하는가?"}], "script": [{"sp": "M", "en": "Hello, everyone. Now that we've departed from Vancouver, I'd like to quickly explain some things to you all. Our ferry ride to Sydney is going to last about an hour and a half. Passengers are asked to remain on the second level of the ferry, where there is plenty of seating. The tour bus will be parked on the lower parking level, but won't be accessible during the ferry trip. Now, keep your eyes open for humpback whales while we travel. Over 100 live in the area, so you're likely to see at least one.", "ko": "안녕하세요, 여러분. 저희가 이제 밴쿠버에서 출발했으므로, 여러분 모두에게 빠르게 몇 가지 사항을 설명해드리고 싶습니다. 시드니로의 저희 여객선 여행은 약 한 시간 반 동안 계속될 예정입니다. 승객분들은 충분한 좌석이 있는 여객선 2층에 남아주시길 바랍니다. 관광 버스는 한층 아래의 주차장에 주차되어 있지만, 여객선 여행 중에는 접근하실 수 없을 것입니다. 이제, 여행하는 동안 혹등고래들을 보기 위해 두 눈을 크게 뜨고 계시길 바랍니다. 100마리 이상이 이 지역에 살고 있으니, 적어도 한 마리는 보실 수 있을 것입니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test04_74-76.mp3", "qs": [{"n": 74, "q": "Who most likely are the listeners?", "opts": ["Post office workers", "Corporate receptionists", "Hotel guests", "Apartment tenants"], "ans": 3, "ko": "청자들은 누구인 것 같은가?"}, {"n": 75, "q": "What problem does the speaker mention?", "opts": ["Outgoing mail can no longer be left at a desk.", "Access to a building is going to be restricted.", "Some packages have gone missing.", "Some staff are not able to carry out a task."], "ans": 1, "ko": "화자는 어떤 문제를 언급하는가?"}, {"n": 76, "q": "According to the speaker, why will slips be left in mail slots?", "opts": ["To request signatures from renters", "To inform people about parcels", "To provide updates on a project", "To collect votes on a proposal"], "ans": 1, "ko": "화자에 따르면, 왜 우편물 투입구에 쪽지들이 남겨질 것인가?"}], "script": [{"sp": "W", "en": "Next on the agenda for this month's meeting is the issue of package deliveries. As you all know, our apartment building will soon be changing its security policy, and delivery people will no longer be allowed to go past the lobby. Consequently, a new system is needed to make sure you all get your packages. Beginning next month, our daytime receptionist will accept parcels on everyone's behalf and leave a slip in individuals' mail slots notifying them about the delivery. Items can be retrieved at the front desk at residents' convenience.", "ko": "이번 달 회의의 다음 안건은 소포 배송에 대한 문제입니다. 여러분 모두 아시다시피, 저희 아파트 건물이 곧 보안 정책이 바뀔 것이고, 배송 기사들은 로비를 지나서 가는 것이 더 이상 허용되지 않을 것입니다. 따라서, 여러분 모두가 소포를 확실히 받으시도록 새로운 제도가 필요합니다. 다음 달부터, 우리 주간 접수 담당자가 모든 사람들을 대신하여 소포를 수령할 것이고 개인 우편물 투입구에 쪽지를 남겨서 배송에 대해 알려드릴 것입니다. 물품들은 주민분들이 편하실 때에 안내 데스크에서 회수하실 수 있습니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test04_77-79.mp3", "qs": [{"n": 77, "q": "Where do the listeners work?", "opts": ["At a construction company", "At a law office", "At a conference center", "At a government agency"], "ans": 1, "ko": "청자들은 어디에서 일하는가?"}, {"n": 78, "q": "What is mentioned about Sandra Boyd?", "opts": ["She has been transferred.", "She coordinated some repairs.", "She is a personal assistant.", "She reported some issues."], "ans": 0, "ko": "Sandra Boyd에 관해 무엇이 언급되는가?"}, {"n": 79, "q": "What does the speaker mean when he says, \"we have scheduled it for Saturday afternoon\"?", "opts": ["The listeners will not participate in an event.", "The listeners will work overtime.", "The listeners will not be disturbed.", "The listeners will be provided with instructions."], "ans": 2, "ko": "화자는 \"저희는 그것을 토요일 오후로 일정을 잡았습니다\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Hey, everyone. Can I have your attention for a moment? I want to let you know that workers will be stopping by our law firm to make some repairs. After Sandra Boyd cleared out her belongings in preparation for her move to our Dallas branch, some water damage was discovered in her old office. Anyway, the workers will locate the source of the leak, and replace a section of a wall. The work will likely be very noisy, so we have scheduled it for Saturday afternoon.", "ko": "안녕하세요, 여러분. 잠시 모두 주목해주시겠습니까? 작업자들이 수리를 하기 위해 우리 법률 사무소에 들를 것임을 알려드리고 싶습니다. Sandra Boyd가 댈러스 지점으로의 전근을 준비하기 위해 그녀의 소지품들을 치운 후, 그녀의 원래 사무실에서 약간의 누수 피해가 발견되었습니다. 어쨌든, 작업자들은 누수의 원인을 찾고, 벽의 한 부분을 교체할 것입니다. 작업이 매우 시끄러울 것 같아서, 저희는 그것을 토요일 오후로 일정을 잡았습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test04_80-82.mp3", "qs": [{"n": 80, "q": "What did the speaker do last month?", "opts": ["Organized a team meeting", "Shared an idea with personnel", "Canceled a pending order", "Handed out some business cards"], "ans": 1, "ko": "화자는 지난달에 무엇을 했는가?"}, {"n": 81, "q": "What does the speaker mean when she says, \"the paper quality was very poor\"?", "opts": ["A service will not be used.", "Some materials must be redesigned.", "A complaint will be made.", "Some samples have been sent back."], "ans": 0, "ko": "화자는 \"종이의 품질이 매우 떨어졌어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 82, "q": "What does the speaker recommend?", "opts": ["Working a longer shift than usual", "Sharing some ideas with the group", "Attending a professional gathering", "Moving back a project deadline"], "ans": 2, "ko": "화자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Before we return to work, I have a couple more points to mention quickly. First, do you all remember when I said I was thinking about having business cards printed for the entire staff at our advertising agency? I told you about the idea last month. Well, the company I looked into was disappointing. I received some sample cards, but the paper quality was very poor, so I'll contact other companies. I also want to talk about the free cultural awareness training session that is being held two weeks from now. It's open to professionals in any field, and it will take place at the Lowland Convention Center. It'd be good for each of you to participate.", "ko": "업무로 돌아가기 전에, 빠르게 언급할 몇 가지 점들이 더 있습니다. 첫 번째로, 제가 우리 광고 대행사의 전 직원을 위해 명함을 인쇄하는 것에 대해 생각하고 있다고 말했던 것을 모두 기억하시나요? 저는 지난달에 이 방안에 대해 말씀드렸어요. 음, 제가 알아본 회사는 실망스러웠습니다. 제가 견본 명함들을 받았지만 종이의 품질이 매우 떨어져서, 다른 회사들에 연락할 거예요. 저는 앞으로 2주 후에 열릴 무료 문화 인식 교육에 관해서도 이야기하고 싶습니다. 이것은 어떤 분야의 전문가들에게도 열려 있으며, Lowland 컨벤션 센터에서 개최될 것입니다. 여러분 모두가 참여하시면 좋을 것 같습니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test04_83-85.mp3", "qs": [{"n": 83, "q": "According to the speaker, what did Jason Ferguson do?", "opts": ["Gave a talk", "Joined an association", "Founded a publication", "Accepted a prize"], "ans": 0, "ko": "화자에 따르면, Jason Ferguson은 무엇을 했는가?"}, {"n": 84, "q": "What is the Career Achievement Award given for?", "opts": ["Raising the standard of journalism", "Creating successful marketing campaigns", "Increasing magazine subscriptions", "Developing innovative business practices"], "ans": 0, "ko": "직업 공로상은 무엇에 대해 수여되는가?"}, {"n": 85, "q": "What will probably happen next?", "opts": ["Some nominees will be named.", "Some group photographs will be taken.", "A brief video will be shown.", "A recipient will come on stage."], "ans": 3, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "That was a wonderful speech that Jason Ferguson just gave. Um . . . the next part of tonight's program is the presentation of the Career Achievement Award. Each year at this gathering, we honor a member of our industry who has raised the standards of journalism through many years of hard work. This year, our association has decided to recognize an individual who started out as a reporter and went on to write articles for news magazines. Please congratulate the winner, Emmanuel Walker.", "ko": "지금까지 Jason Ferguson의 멋진 연설이었습니다. 음… 오늘 밤 프로그램의 다음 순서는 직업 공로상의 수여입니다. 매년 이 모임에서, 저희는 수년간의 노고를 통해 언론계의 수준을 높인 우리 업계의 구성원에게 영예를 드립니다. 올해, 저희 협회는 기자로 시작하여 나아가 뉴스 잡지의 기사를 써온 한 분을 표창하기로 결정하였습니다. 수상자인 Emmanuel Walker를 축하해주십시오."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test04_86-88.mp3", "qs": [{"n": 86, "q": "What prevented the speaker from calling sooner?", "opts": ["A business trip", "A medical appointment", "Luncheon arrangements", "Inspection preparations"], "ans": 3, "ko": "무엇이 화자가 더 일찍 전화하지 못하게 하였는가?"}, {"n": 87, "q": "What does the speaker mean when he says, \"The shipment is scheduled to arrive tomorrow\"?", "opts": ["An order was placed on time.", "A delivery is behind schedule.", "A job can begin as planned.", "A fee was paid to expedite an order."], "ans": 2, "ko": "화자는 \"배송은 내일 도착할 예정입니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 88, "q": "What will a worker give to the listener?", "opts": ["A revised schedule", "A set of blueprints", "A box of supplies", "A billing statement"], "ans": 3, "ko": "작업자는 청자에게 무엇을 줄 것인가?"}], "script": [{"sp": "M", "en": "Good morning, Ms. Prescott. It's Adam Morris from Oakridge Pools calling. Sorry for not returning your call yesterday, but I was tied up preparing a site for a final inspection. Anyway, I want to let you know about a change related to your pool. Last Wednesday, I told you I need to put off the project because the tiles for the pool's edge weren't available until next month. Well, there was a miscommunication with my supplier. The shipment is scheduled to arrive tomorrow. If you're okay with it, my crew members will head over to your property on Thursday morning. One of them will give you the initial invoice.", "ko": "안녕하세요, Ms. Prescott. 저는 Oakridge Pools사의 Adam Morris입니다. 어제 회신 전화를 드리지 못해 죄송합니다만, 저는 마지막 점검을 위해 현장을 준비하느라 너무 바빴습니다. 어쨌든, 귀하의 수영장과 관련된 변경 사항에 대해 알려드리고자 합니다. 지난 수요일에, 제가 수영장의 가장자리를 위한 타일을 다음 달까지 구할 수 없기 때문에 프로젝트를 미뤄야 한다고 말씀드렸습니다. 음, 저희 공급업체와의 의사소통에 오류가 있었습니다. 배송은 내일 도착할 예정입니다. 그것이 괜찮으시다면, 제 작업반 직원들이 목요일 오전에 귀하의 건물로 가겠습니다. 그들 중 한 명이 귀하께 초기 송장을 드릴 것입니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test04_89-91.mp3", "qs": [{"n": 89, "q": "What is mentioned about the game on August 18?", "opts": ["It will be streamed online.", "It will begin later than expected.", "It has been moved to a new venue.", "It has generated a lot of interest."], "ans": 3, "ko": "8월 18일의 경기에 대해 무엇이 언급되는가?"}, {"n": 90, "q": "According to the speaker, what did David Polanski do last week?", "opts": ["Met with another team's coach", "Purchased additional uniforms", "Organized a team practice", "Spoke with a media representative"], "ans": 3, "ko": "화자에 따르면, David Polanski는 지난주에 무엇을 했는가?"}, {"n": 91, "q": "What will probably happen next?", "opts": ["An interview will be conducted.", "An advertisement will be played.", "A weather forecast will be given.", "A game score will be announced."], "ans": 1, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "W", "en": "In sports news, the Bridgeport Rockets will play the Greenville Tigers at 4 P.M. on August 18 in the championship game of the New England Soccer League Finals. There's a lot of interest in this match, and it has already sold out. During an interview on Weekly Sports Update last week, David Polanski, the coach of the Rockets, said that his team has signed several highly skilled players this season, which will give it an advantage. I will talk a bit about them after a brief message from our sponsor. Stay tuned.", "ko": "스포츠 뉴스로, Bridgeport Rockets는 8월 18일 오후 4시에 뉴잉글랜드 축구 리그 결승전에서 Greenville Tigers와 결승 경기를 할 것입니다. 이 경기에 대한 관심이 매우 높으며, 경기는 이미 매진되었습니다. 지난주에 Weekly Sports Update에서의 인터뷰에서, Rockets의 코치인 David Polanski는 그의 팀이 이번 시즌에 매우 숙련된 여러 명의 선수들과 계약했고, 이는 팀에 유리한 점을 가져다줄 것이라고 말했습니다. 광고주로부터의 짧은 광고 방송 후에 그들에 대해 조금 이야기하겠습니다. 채널을 고정해 주십시오."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test04_92-94.mp3", "qs": [{"n": 92, "q": "What was sent out two weeks ago?", "opts": ["A newsletter", "A registration form", "A contract", "A reminder letter"], "ans": 3, "ko": "2주 전에 무엇이 발송되었는가?"}, {"n": 93, "q": "According to the speaker, what can the listener do online?", "opts": ["Read a user agreement", "Update personal information", "Submit a payment", "Learn about loan options"], "ans": 2, "ko": "화자에 따르면, 청자는 온라인으로 무엇을 할 수 있는가?"}, {"n": 94, "q": "Why would the listener contact the speaker?", "opts": ["To make an inquiry", "To close an account", "To activate a credit card", "To apply for a mortgage"], "ans": 0, "ko": "청자는 왜 화자에게 연락할 것인가?"}], "script": [{"sp": "M", "en": "Andrew Cummings, my name is Matthew Schmitt, and I'm contacting you on behalf of Gladstone Bank. Two weeks ago, we mailed you a notice about your car loan, but you missed your scheduled monthly payment of $220. As a result, a surcharge of $20 will be added to the fee. Please pay the new total by this Friday. You can do so online or over the phone. Meeting this deadline will prevent further penalties. If you have any questions about the matter, you can reach me directly at 555-8342. Thank you.", "ko": "Andrew Cummings, 제 이름은 Matthew Schmitt이며, Gladstone 은행을 대표하여 귀하께 연락드립니다. 2주 전에, 귀하의 자동차 구입 자금 대출에 관한 공지를 메일로 보내드렸으나, 220달러의 예정된 월 지불 금액을 지불하지 않으셨습니다. 그 결과, 요금에 20달러의 추가 요금이 더해질 것입니다. 이번 주 금요일까지 새로운 총액을 지불해주시기 바랍니다. 귀하는 온라인이나 전화로 그렇게 하실 수 있습니다. 이 기한을 맞추는 것이 그 이상의 위약금을 방지할 것입니다. 이 사항에 대해 궁금한 점이 있으시면, 555-8342로 저에게 바로 연락하실 수 있습니다. 감사합니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test04_95-97.mp3", "qs": [{"n": 95, "q": "What is a new feature of the MarbleBot smartphone?", "opts": ["A fast processor", "A fingerprint sensor", "A wide screen", "An advanced camera"], "ans": 1, "ko": "MarbleBot 스마트폰의 새로운 특징은 무엇인가?"}, {"n": 96, "q": "Look at the graphic. Which model is the MarbleBot's main competitor?", "opts": ["Xizang 200", "Jannat Z4", "SpeedyCall", "Adamello"], "ans": 1, "ko": "시각 자료를 보시오. MarbleBot의 주요 경쟁 상대는 어떤 기종인가?"}, {"n": 97, "q": "What was released by GadgetAssessor.com?", "opts": ["A company profile", "A product manual", "A list of ranked devices", "A series of photos"], "ans": 2, "ko": "GadgetAssessor.com에 의해 무엇이 발표되었는가?"}], "script": [{"sp": "M", "en": "The latest version of the MarbleBot is our best-selling smartphone ever. Like our previous models in this line, it has a fast processor and an advanced camera. But customers have been really impressed by the new fingerprint sensor. They also appreciate the long battery life. Even our device's main competitor only has an active battery life of about 15 hours, so we're well ahead in that respect. And for those who haven't heard, GadgetAssessor.com recently released its latest series of product ratings. Among a list of a dozen cell phones, the MarbleBot was ranked No. 1. The technology blog is highly respected, so this is great news. Let's figure out some creative ways to publicize this achievement.", "ko": "MarbleBot의 최신 버전은 이제까지 저희의 가장 잘 팔리는 스마트폰입니다. 이 라인의 이전 기종들처럼, 그것은 빠른 처리 장치와 고급 카메라를 가지고 있습니다. 하지만 고객들은 새로운 지문 센서에 매우 깊은 인상을 받았습니다. 그들은 또한 긴 배터리 수명을 높이 평가합니다. 우리 기기의 주요 경쟁 상대조차도 겨우 약 15시간의 유효 배터리 수명을 가지고 있으므로, 우리는 그 측면에서 훨씬 앞서 있습니다. 그리고 전해 듣지 못한 분들을 위해, GadgetAssessor.com에서 최근에 제품 순위의 최신 시리즈를 발표했습니다. 12개의 휴대폰 목록에서, MarbleBot은 1위를 차지하였습니다. 이 기술 블로그는 매우 높이 평가 받고 있으므로, 이는 아주 좋은 소식입니다. 이 성과를 홍보하기 위한 창의적인 방법들을 생각해봅시다."}], "gimg": "hk2_t4_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "캐나다식 발음", "audio": "Test04_98-100.mp3", "qs": [{"n": 98, "q": "According to the speaker, what does the listener plan to do tomorrow?", "opts": ["Test drive a vehicle", "Go on a road trip", "Secure a rental car", "Review a billing statement"], "ans": 1, "ko": "화자에 따르면, 청자는 내일 무엇을 할 계획인가?"}, {"n": 99, "q": "Look at the graphic. Which component has an issue that needs to be addressed?", "opts": ["Headlights", "Brake pads", "Timing belt", "Exhaust system"], "ans": 2, "ko": "시각 자료를 보시오. 무슨 부품이 처리되어야 할 문제를 가지는가?"}, {"n": 100, "q": "Why does the speaker want to talk to the listener?", "opts": ["To offer an explanation", "To discuss alternative options", "To explain promotion conditions", "To arrange a pick-up time"], "ans": 0, "ko": "화자는 왜 청자와 이야기하고 싶어 하는가?"}], "script": [{"sp": "M", "en": "Ms. Witten, it's Ryan Tumbler from Lyndale Automotive. Since your family plans to drive from Phoenix to Las Vegas tomorrow, we're prioritizing repairs to your vehicle. As suspected, the exhaust pipe had a hole in it, and the brake pads were worn down. We've replaced those items, as you already said that was fine. Unfortunately, we discovered that another part needs to be replaced. However, the work will be quite costly, so I want to explain the problem to you. After that, you can decide if you want to proceed with repairs. Please call us back at your earliest convenience.", "ko": "Ms. Witten, 저는 Lyndale Automotive의 Ryan Tumbler입니다. 귀하의 가족께서 내일 피닉스에서 라스베이거스까지 자동차로 여행하는 것을 계획하고 계시기 때문에, 저희는 귀하의 차량에 대한 수리를 우선적으로 처리하고 있습니다. 짐작했던 대로, 배기관 안에 구멍이 있었고, 브레이크 패드는 마모되어 있었습니다. 이미 괜찮다고 하셨으므로, 저희는 그 물품들을 교체하였습니다. 안타깝게도, 저희는 또다른 부분이 교체되어야 함을 발견했습니다. 그러나, 그 작업은 꽤 비쌀 것이기 때문에, 이 문제에 대해 귀하께 직접 설명해드리고 싶습니다. 그 후에, 귀하께서 수리를 진행하고 싶으신지 결정하실 수 있습니다. 가능한 한 빨리 다시 전화해주시기 바랍니다."}], "gimg": "hk2_t4_g98.jpg"}]};
